 * createRateLimiter — TRUE sliding window rate limiting middleware for Express.
 *
 * Unlike a fixed-window limiter (which buckets requests into discrete intervals
 * and resets the counter at interval boundaries — allowing bursts of up to
 * 2*maxRequests across a boundary), this implementation keeps a per-IP log of
 * individual request timestamps. On every request it evicts timestamps older
 * than `windowMs` relative to *now*, so the window continuously slides.
 *
 * @param {Object}  [options]
 * @param {number}  [options.windowMs=60000]    Window size in milliseconds.
 * @param {number}  [options.maxRequests=100]   Max requests allowed per window.
 * @param {number}  [options.cleanupMs=60000]   Janitor sweep interval (ms).
 * @param {(req)=>string} [options.keyGenerator] Custom client-key extractor.
 * @returns {Function & { close: () => void }} Express middleware with a
 *          `close()` method that clears the cleanup timer.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    cleanupMs = 60000,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]>  — array of request timestamps (ms epoch),
  // kept in ascending order (we always push "now", which is monotonic enough).
  const hits = new Map();

  /**
   * Drop all timestamps that fall outside the sliding window ending at `now`.
   * Because timestamps are appended in chronological order, the stale ones are
   * always a prefix of the array — we find the first in-window index and slice.
   * @returns {number[]} the surviving (in-window) timestamps.
   */
  function evictExpired(timestamps, now) {
    const cutoff = now - windowMs;
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) {
      i++;
    }
    return i === 0 ? timestamps : timestamps.slice(i);
  }

  const middleware = function rateLimiter(req, res, next) {
    const key = keyGenerator(req);
    const now = Date.now();

    // 1. Load this client's log and evict everything older than the window.
    const recent = evictExpired(hits.get(key) || [], now);

    // 2. Decide based on how many requests remain inside the sliding window.
    if (recent.length >= maxRequests) {
      // Rejected. The window frees up when its OLDEST surviving request ages
      // out — that's `oldest + windowMs`. Retry-After is the time until then.
      hits.set(key, recent); // persist the trimmed log
      const oldest = recent[0];
      const resetMs = oldest + windowMs;
      const retryAfter = Math.max(1, Math.ceil((resetMs - now) / 1000));

      res.setHeader('X-RateLimit-Limit', String(maxRequests));
      res.setHeader('X-RateLimit-Remaining', '0');
      res.setHeader('X-RateLimit-Reset', String(Math.ceil(resetMs / 1000)));
      res.setHeader('Retry-After', String(retryAfter));

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter,
      });
      return; // Do NOT call next().
    }

    // 3. Allowed — record this request's timestamp and let it through.
    recent.push(now);
    hits.set(key, recent);

    const remaining = maxRequests - recent.length;
    // Reset = when the oldest in-window request expires (window fully slides).
    const resetMs = recent[0] + windowMs;

    res.setHeader('X-RateLimit-Limit', String(maxRequests));
    res.setHeader('X-RateLimit-Remaining', String(remaining));
    res.setHeader('X-RateLimit-Reset', String(Math.ceil(resetMs / 1000)));

    next();
  };

  // --- Memory management -----------------------------------------------------
  // Periodically purge IPs that have had no requests within the last windowMs.
  // Without this, the Map grows unbounded as new IPs arrive and never recur.
  const cleanup = setInterval(() => {
    const now = Date.now();
    for (const [key, timestamps] of hits) {
      const recent = evictExpired(timestamps, now);
      if (recent.length === 0) {
        hits.delete(key);
      } else if (recent.length !== timestamps.length) {
        hits.set(key, recent);
      }
    }
