  if (typeof cleanup.unref === 'function') {
    cleanup.unref();
  }

  // Expose a way to stop the timer (e.g. on graceful shutdown or in tests).
  middleware.close = function close() {
    clearInterval(cleanup);
    hits.clear();
  };

  return middleware;
}

