/**
 * Sliding Window Rate Limiter Middleware for Express.js
 *
 * Implements a TRUE sliding window algorithm: each IP maintains an ordered
 * log of request timestamps.  On every request the log is pruned to the
 * last `windowMs` milliseconds, then the count is compared against
 * `maxRequests`.  There are no fixed-interval resets — the window slides
 * continuously with real time.
 *
 * PROXY NOTE ─────────────────────────────────────────────────────────────
 * `req.ip` returns the left-most IP in the X-Forwarded-For chain when
 * Express's "trust proxy" setting is enabled.  Behind Nginx (as this
 * project is) you should call:
 *
 *   app.set('trust proxy', 1);   // trust one hop (the Nginx reverse proxy)
 *
 * before mounting this middleware, otherwise `req.ip` will always be the
 * loopback address (127.0.0.1) and the limiter will treat ALL clients as
 * a single identity.
 * ─────────────────────────────────────────────────────────────────────────
 */

'use strict';

/**
 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   - Sliding window size in ms (default 1 minute)
 * @property {number} [maxRequests=100]  - Max requests allowed in that window (default 100)
 */

/**
 * @typedef {Object} RateLimiter
 * @property {import('express').RequestHandler} middleware - Mount this on your Express app
 * @property {() => void} close - Call on graceful shutdown to clear the cleanup timer
 */

/**
 * Creates a sliding-window rate limiter.
 *
 * @param {RateLimiterOptions} [options]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000;  // default: 1 minute
  const maxRequests = options.maxRequests ?? 100;     // default: 100 req/window

  if (typeof windowMs !== 'number' || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (typeof maxRequests !== 'number' || maxRequests < 1) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  /**
   * Per-IP timestamp store.
   * Map<string, number[]>  —  each array holds request timestamps in
   * ascending order (oldest first) because we only ever push to the tail.
   */
  const store = new Map();

  // ── Background cleanup ────────────────────────────────────────────────
  // Every 60 s we evict IPs whose entire timestamp log has aged out of the
  // window.  This bounds memory growth: a silent IP is removed on the next
  // tick rather than living in the Map forever.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [ip, timestamps] of store) {
      // Array is oldest-first; if the last element is stale, all are stale.
      if (timestamps[timestamps.length - 1] <= cutoff) {
        store.delete(ip);
      }
    }
  }, 60_000);

  // unref() lets Node.js exit naturally even while this interval is
  // pending — the process won't be kept alive solely by the cleanup timer.
  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
  }

  // ── Middleware ─────────────────────────────────────────────────────────
  /**
   * Express middleware implementing the sliding window check.
   * @type {import('express').RequestHandler}
   */
  function middleware(req, res, next) {
    // req.ip respects Express's "trust proxy" setting (see PROXY NOTE above).
    const ip  = req.ip ?? req.socket?.remoteAddress ?? 'unknown';
    const now = Date.now();
    const windowStart = now - windowMs;

    // 1. Retrieve the existing log for this IP (default to empty array).
    // 2. Slide the window: drop every timestamp that has fallen behind the
    //    cutoff.  Because the array is sorted oldest-first, findIndex gives
    //    us the first still-valid position in O(n) but typically O(1) for
    //    bursty-then-quiet clients.
    const raw        = store.get(ip) ?? [];
    const firstValid = raw.findIndex(ts => ts > windowStart);
    const timestamps = firstValid === -1 ? [] : raw.slice(firstValid);
    // `timestamps` now contains only requests within the sliding window.

    // ── Over-limit path ──────────────────────────────────────────────────
    if (timestamps.length >= maxRequests) {
      // The client must wait until the oldest in-window timestamp slides out
      // before a slot opens up.
      const retryAfterMs  = timestamps[0] + windowMs - now;
      const retryAfterSec = Math.max(1, Math.ceil(retryAfterMs / 1000));

      res.set('Retry-After', String(retryAfterSec));
      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      // next() is intentionally NOT called.
    }

    // ── Under-limit path ─────────────────────────────────────────────────
    timestamps.push(now);
    store.set(ip, timestamps);

    // X-RateLimit-Reset: the epoch second at which the oldest in-window
    // request will expire, freeing the first slot.
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.set('X-RateLimit-Limit',     String(maxRequests));
    res.set('X-RateLimit-Remaining', String(maxRequests - timestamps.length));
    res.set('X-RateLimit-Reset',     String(resetEpochSec));

    next();
  }

  // ── Cleanup handle ────────────────────────────────────────────────────
  /**
   * Stop the background cleanup interval.
   * Call during graceful shutdown (redundant if unref() worked, but explicit
   * and safe to call multiple times).
   */
  function close() {
    clearInterval(cleanupInterval);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
